\u0066\u0021\u002e\u0041\u0078\u0070\u0057\u0045\u004d\u0058\u0029\u0043\u0031\u003d\u0071\u0044\u003b\u002a\u0039\u0044\u003a\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u004f\u0055\u004a\u0040\u0044\u0050\u007d\u0035\u0041\u003a\u0021\u0052\u006a\u003d\u0035\u006d\u0026\u007b\u0071\u004c\u0044\u0055\u0050\u0074\u004e\u004e\u004d\u0044\u007a\u007d\u0040\u0057\u007c\u0042\u0021\u0069\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0050\u0074\u004e\u004e\u004d\u0044\u007a\u007d\u0040\u0057\u007c\u0042\u0021\u0069\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0050\u0074\u004e\u004e\u004d\u0044\u007a\u007d\u0040\u0057\u0066\u005b\u0029\u0066\u0032\u006d\u0040\u0065\u004d\u0058\u0050\u0074\u0035\u003d\u0068\u0044\u003e\u002a\u0045\u0040\u007e\u006b\u003c\u0066\u0052\u0064\u003a\u0054\u0031\u003d\u0042\u0044\u006c\u0055\u0053\u0040\u0045\u0036\u003c\u0035\u0060\u0040\u005b\u0046\u0046\u0058\u006d\u0041\u0058\u003e\u0071\u004c\u0046\u0055\u007a\u0022\u007d\u004e\u004d\u0044\u007a\u007d\u0040\u0057\u007c\u0042\u0021\u0069\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0050\u0074\u004e\u004e\u004d\u0044\u007a\u007d\u0040\u0057\u007c\u0042\u0021\u0069\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0060\u0074\u004e\u004e\u006e\u0044\u0037\u007d\u0057\u006c\u003f\u005e\u007c\u0049\u0026\u0073\u0059\u0067\u003e\u004b\u0024\u0043\u0053\u002b\u0053\u0044\u0035\u002a\u0068\u0040\u006b\u0050\u003b\u0066\u0052\u0064\u003a\u0054\u0031\u003d\u0071\u0044\u006c\u0055\u004a\u0040\u0059\u006b\u0029\u0066\u0072\u002a\u0021\u0052\u002a\u002b\u0035\u006d\u0063\u002b\u0073\u0053\u002b\u0055\u0050\u0074\u007b\u004e\u0023\u0060\u005d\u007d\u0057\u006c\u0035\u0042\u0040\u0053\u0078\u0070\u0079\u0074\u004c\u0033\u002c\u006f\u0031\u003d\u002b\u0044\u0061\u007a\u0043\u0040\u003c\u0055\u003c\u0035\u0021\u004f\u005d\u0028\u007a\u007a\u0039\u0063\u0053\u003e\u004e\u0067\u0054\u0049\u0060\u0074\u002b\u004e\u005b\u002c\u0038\u007d\u006f\u0061\u003f\u005e\u007c\u0049\u0078\u0070\u004c\u0053\u004c\u0033\u006e\u0074\u0053\u002b\u006b\u0044\u004f\u0055\u0068\u0044\u003a\u0070\u0054\u0074\u004c\u0033\u0055\u0074\u0031\u003d\u0071\u0044\u003e\u002a\u0043\u0040\u0024\u0055\u003b\u0066\u006f\u007e\u005b\u0046\u0072\u007b\u0039\u0063\u0053\u003e\u0071\u004c\u004d\u0049\u0029\u0022\u002f\u004e\u006f\u0037\u005e\u007d\u006f\u0061\u0035\u0042\u0041\u0052\u0078\u0070\u004e\u006f\u004c\u0033\u0035\u006f\u0031\u003d\u0054\u0044\u0055\u007a\u0043\u0040\u0061\u005d\u003b\u0066\u0058\u006c\u005b\u0046\u0062\u004e\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0060\u0074\u005e\u004e\u003b\u003f\u003e\u007d\u0040\u0057\u007c\u0042\u0021\u0069\u0039\u0063\u0066\u0034\u0071\u004c\u0077\u007a\u0075\u0066\u002e\u0056\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u006c\u0055\u0053\u0040\u004e\u006b\u0029\u0066\u002e\u0056\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u0071\u0044\u003e\u002a\u0043\u0040\u0044\u0050\u0026\u0035\u002a\u0056\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u006c\u0055\u0053\u0040\u004e\u006b\u0029\u0066\u002e\u0056\u0026\u0073\u003d\u0054\u003e\u004b\u0075\u0043\u0031\u003d\u004a\u0044\u007a\u0062\u0053\u0040\u004e\u006b\u003b\u0035\u004f\u0077\u005d\u0028\u0065\u004b\u0039\u0063\u0043\u003d\u0079\u0077\u004e\u006b\u0029\u0066\u002e\u0056\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u006c\u0055\u0065\u0040\u0035\u005b\u0026\u0066\u002e\u0056\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u006c\u0055\u0053\u0040\u0058\u004e\u0029\u0066\u0058\u006c\u005b\u0046\u0063\u007e\u0039\u0063\u0036\u002b\u0071\u004c\u0028\u0055\u0045\u0022\u007b\u004e\u0043\u006e\u003e\u007d\u0031\u0070\u007c\u0042\u0021\u0069\u0039\u0063\u0043\u003d\u0071\u004c\u0044\u0055\u0045\u0022\u0031\u004e\u007c\u002c\u005d\u007d\u0049\u0079\u007c\u0042\u002f\u004d\u0078\u0070\u003d\u0054\u004c\u0033\u0055\u0074\u0031\u003d\u006b\u0044\u006c\u0055\u0053\u0040\u004e\u006b\u003c\u0057\u004d\u0076\u004f\u0057\u0045\u0071\u0078\u0072\u0064\u006c\u006f\u0040\u0050\u006b\u003c\u0035\u0067\u007e\u005a\u0038\u0045\u0023\u0030\u007b\u004d\u0034\u0068\u0049\u0066\u0055\u0052\u0050\u0075\u004e\u0052\u003f\u007b\u007d\u0036\u002b\u0061\u0021\u006a\u0045\u006d\u004a\u0061\u0053\u0024\u006f\u0026\u0074\u005e\u0031\u0048\u0044\u0064\u006c\u0043\u0040\u0070\u004f\u0026\u0035\u0043\u004c\u005a\u0038\u0031\u0034\u0030\u007b\u006f\u0034\u0068\u0049\u004b\u0055\u0052\u0050\u0075\u004e\u0023\u004d\u007b\u007d\u007a\u0033\u0061\u0021\u0023\u0064\u0073\u0056\u0029\u0063\u007e\u0054\u005b\u0071\u004a\u0024\u003d\u004e\u007e\u0030\u005e\u007d\u0021\u0058\u0061\u0021\u004a\u006a\u006d\u004a\u007e\u0053\u0024\u006f\u0029\u0043\u005e\u0031\u0039\u0044\u0037\u002e\u006f\u0040\u005f\u0053\u003c\u0035\u0039\u0034\u005a\u0038\u0051\u0030\u0030\u007b\u0022\u002b\u0068\u0049\u003c\u0055\u0052\u0050\u002f\u004e\u003b\u0051\u007b\u007d\u0062\u0068\u0066\u0021\u004a\u006a\u006d\u004a\u007e\u0053\u0024\u006f\u0036\u0074\u005e\u0031\u005a\u0044\u0064\u006c\u0043\u0040\u0050\u006b\u003c\u0035\u0070\u0059\u0021\u0056\u007a\u0072\u0051\u0076\u007c\u004c\u005e\u0031\u005a\u0044\u0064\u006c\u006f\u0040\u0049\u005a\u0026\u0035\u0068\u004f\u005a\u0038\u004b\u002b\u0030\u007b\u007c\u007a\u0068\u0049\u007c\u0055\u004a\u0024\u0025\u004e\u0041\u0043\u0025\u007d\u004b\u006e\u0066\u0021\u004a\u006a\u006d\u004a\u007e\u0053\u0024\u006f\u0037\u0043\u005e\u0031\u004c\u0044\u0037\u002e\u004a\u0040\u005f\u0053\u003c\u0035\u0070\u0059\u005a\u0038\u0052\u007e\u0030\u007b\u0026\u0034\u0068\u0049\u0024\u0055\u0052\u0050\u003d\u004e\u0023\u004d\u007b\u007d\u0021\u0058\u0035\u0056\u0045\u0071\u0047\u0069\u007c\u004c\u005e\u0031\u0043\u0044\u0025\u0068\u0052\u0040\u0059\u007a\u003c\u0035\u0043\u004c\u005a\u0038\u002b\u007a\u0030\u007b\u005d\u002b\u0068\u0049\u0078\u0055\u004a\u0024\u0025\u004e\u0041\u0043\u0025\u007d\u005b\u0050\u0066\u0021\u003e\u0071\u006d\u004a\u0061\u0053